using Microsoft.Playwright;
using ScraperBackendService.Configuration;
using ScraperBackendService.Core.Net;
using ScraperBackendService.AntiCloudflare;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using ScraperBackendService.Core.Logging;

namespace ScraperBackendService.Extensions;/// <summary>/// Service registration extension methods for dependency injection configuration./// </summary>public static class ServiceCollectionExtensions{    public static IServiceCollection AddScrapingServices(this IServiceCollection services, ServiceConfiguration config)    {        // Register configuration options for dependency injection        services.Configure<ServiceConfiguration>(opt =>        {            opt.Port = config.Port;            opt.Host = config.Host;            opt.AuthToken = config.AuthToken;            opt.TokenHeaderName = config.TokenHeaderName;            opt.RequestTimeoutSeconds = config.RequestTimeoutSeconds;            opt.MaxConcurrentRequests = config.MaxConcurrentRequests;            opt.RateLimitSeconds = config.RateLimitSeconds;            opt.EnableAggressiveMemoryOptimization = config.EnableAggressiveMemoryOptimization;            opt.ChallengeAutoWaitSeconds = config.ChallengeAutoWaitSeconds;            opt.ChallengeAutoWaitSlowSeconds = config.ChallengeAutoWaitSlowSeconds;        });        // Register PlaywrightService as singleton to manage browser lifecycle        services.AddSingleton<PlaywrightService>();        // Register Playwright browser as singleton with proper disposal        services.AddSingleton<IBrowser>(sp =>        {            var playwrightService = sp.GetRequiredService<PlaywrightService>();            return playwrightService.GetBrowserAsync().GetAwaiter().GetResult();        });        // Register PlaywrightContextManager as singleton using the browser instance        services.AddSingleton<PlaywrightContextManager>(sp =>        {            var browser = sp.GetRequiredService<IBrowser>();            var logger = sp.GetRequiredService<ILogger<PlaywrightContextManager>>();            var options = new PlaywrightClientOptions            {                ChallengeAutoWaitMs = config.ChallengeAutoWaitSeconds * 1000,                ChallengeAutoWaitSlowMs = config.ChallengeAutoWaitSlowSeconds * 1000,                EnableManualChallengeResolution = config.EnableManualChallengeResolution,                ManualChallengeTimeoutSeconds = config.ManualChallengeTimeoutSeconds,                ManualChallengeWindowWidth = config.ManualChallengeWindowWidth,                ManualChallengeWindowHeight = config.ManualChallengeWindowHeight,                EnableCookiePersistence = config.EnableCookiePersistence,                AutoLoadCookiesOnContextCreation = config.AutoLoadCookiesOnContextCreation,                CookieStorageDirectory = config.CookieStorageDirectory            };            return new PlaywrightContextManager(browser, logger, options);        });        // Register ChallengeDetector        services.AddSingleton<ChallengeDetector>(sp => {            var logger = sp.GetRequiredService<ILogger<ChallengeDetector>>();            return new ChallengeDetector(logger);        });        // Register PlaywrightNetworkClient using context manager        services.AddScoped<PlaywrightNetworkClient>(sp =>        {            var ctxMgr = sp.GetRequiredService<PlaywrightContextManager>();            var logger = sp.GetRequiredService<ILogger<PlaywrightNetworkClient>>();            var detector = sp.GetRequiredService<ChallengeDetector>();            return new PlaywrightNetworkClient(ctxMgr, logger, detector);        });        // Register HttpNetworkClient via IHttpClientFactory        services.AddHttpClient<HttpNetworkClient>();        // =============== Register All Providers ===============        // Provider registration is managed by ProviderRegistry        foreach (var providerConfig in Providers._Registry.ProviderRegistry.GetAllProviders())        {            Providers._Registry.ProviderRegistry.RegisterProvider(services, providerConfig, config);        }
        return services;
    }
}